        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – invalid input (DataRow)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.00, 1, 1.01,  DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidInput_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (method source)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountCases), DynamicDataSourceType.Method,
        DynamicDataDisplayName = nameof(GetApplyDiscountDisplayName))]
    public void ApplyDiscount_ReturnsExpectedResult(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> ApplyDiscountCases()
    {
        yield return [100m, 0m, 100m];     // no discount
        yield return [100m, 10m, 90m];     // 10% off
        yield return [100m, 50m, 50m];     // half off
        yield return [100m, 100m, 0m];     // full discount
        yield return [49.99m, 25m, 37.4925m]; // fractional result
        yield return [0m, 50m, 0m];        // zero price
    }

    private static string GetApplyDiscountDisplayName(MethodInfo methodInfo, object[] data)
        => $"Price={data[0]}, Discount={data[1]}% → {data[2]}";

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (property source)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountInvalidCases), DynamicDataSourceType.Property)]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRangeException(
        decimal price, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));
    }

    public static IEnumerable<object[]> ApplyDiscountInvalidCases =>
    [
        [100m, -1m],   // below 0
        [100m, 101m],  // above 100
    ];
}

